import React, { useState } from 'react';
import { Video, Mic, MicOff, VideoOff, Phone } from 'lucide-react';

export function VideoChat({ isOpen, onClose }) {
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOn, setIsVideoOn] = useState(true);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/90 z-50">
      <div className="h-full flex flex-col">
        {/* Video Area */}
        <div className="flex-1 flex justify-center items-center">
          <div className="relative w-full max-w-4xl aspect-video bg-gray-800 rounded-lg">
            {!isVideoOn && (
              <div className="absolute inset-0 flex items-center justify-center">
                <Video className="text-gray-400" size={64} />
              </div>
            )}
          </div>
        </div>

        {/* Controls */}
        <div className="p-6 flex justify-center gap-6">
          <button 
            onClick={() => setIsMuted(!isMuted)}
            className={`p-4 rounded-full ${isMuted ? 'bg-red-500' : 'bg-gray-600'} hover:opacity-80`}
          >
            {isMuted ? <MicOff color="white" /> : <Mic color="white" />}
          </button>

          <button 
            onClick={() => setIsVideoOn(!isVideoOn)}
            className={`p-4 rounded-full ${!isVideoOn ? 'bg-red-500' : 'bg-gray-600'} hover:opacity-80`}
          >
            {isVideoOn ? <Video color="white" /> : <VideoOff color="white" />}
          </button>

          <button 
            onClick={onClose}
            className="p-4 rounded-full bg-red-500 hover:bg-red-600"
          >
            <Phone color="white" />
          </button>
        </div>
      </div>
    </div>
  );
}
